1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  const alive = new Set(cells.map(cellKey));
13	  const neighborsOf = ([x, y]: Cell): Cell[] =>
14	    NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
15	  const liveNeighborCount = (cell: Cell): number =>
16	    neighborsOf(cell).filter((n) => alive.has(cellKey(n))).length;
17	
18	  const candidates = new Map<string, Cell>(
19	    cells.flatMap((cell) => [cell, ...neighborsOf(cell)]).map((c) => [cellKey(c), c])
20	  );
21	
22	  const isAliveNext = (cell: Cell): boolean => {
23	    const n = liveNeighborCount(cell);
24	    return alive.has(cellKey(cell)) ? n === 2 || n === 3 : n === 3;
25	  };
26	
27	  return [...candidates.values()].filter(isAliveNext);
28	}
