1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("empty input returns empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single live cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent live cells both die (underpopulation, 1 neighbor each) — [(0,1),(1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life is unchanged — [(0,0),(1,0),(0,1),(1,1)] stays the same", () => {
15	    const block: [number, number][] = [
16	      [0, 0],
17	      [1, 0],
18	      [0, 1],
19	      [1, 1],
20	    ];
21	    const result = nextGeneration(block);
22	    expect(result.sort()).toEqual(block.sort());
23	  });
24	  it("live cell with 2 neighbors survives (Rule 2 survival) — live cell with 2 live neighbors stays alive", () => {
25	    // (0,0),(1,0),(2,0): center (1,0) is live with 2 live neighbors → survives
26	    const result = nextGeneration([
27	      [0, 0],
28	      [1, 0],
29	      [2, 0],
30	    ]);
31	    expect(result).toContainEqual([1, 0]);
32	  });
33	  it("live cell with 4 neighbors dies (Rule 3 overpopulation) — center of plus+corners dies", () => {
34	    // Cells: (0,0),(2,0),(1,1),(0,2),(2,2) — center (1,1) has 4 diagonal neighbors
35	    const result = nextGeneration([
36	      [0, 0],
37	      [2, 0],
38	      [1, 1],
39	      [0, 2],
40	      [2, 2],
41	    ]);
42	    expect(result).not.toContainEqual([1, 1]);
43	  });
44	  it("dead cell with exactly 3 live neighbors becomes alive (Rule 4 reproduction) — L-shape becomes block", () => {
45	    // L-shape: (0,0), (1,0), (0,1). Dead (1,1) has 3 neighbors → becomes alive
46	    const result = nextGeneration([
47	      [0, 0],
48	      [1, 0],
49	      [0, 1],
50	    ]);
51	    expect(result).toContainEqual([1, 1]);
52	  });
53	  it("blinker oscillates from vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
54	    const result = nextGeneration([
55	      [0, 0],
56	      [0, 1],
57	      [0, 2],
58	    ]);
59	    const sortKey = (c: [number, number]) => `${c[0]},${c[1]}`;
60	    expect(result.slice().sort((a, b) => sortKey(a).localeCompare(sortKey(b)))).toEqual(
61	      [
62	        [-1, 1],
63	        [0, 1],
64	        [1, 1],
65	      ].sort((a, b) => sortKey(a).localeCompare(sortKey(b)))
66	    );
67	  });
68	  it("handles negative coordinates — blinker shifted into negative space", () => {
69	    // Vertical blinker at x=-5 → horizontal at y=-4
70	    const result = nextGeneration([
71	      [-5, -5],
72	      [-5, -4],
73	      [-5, -3],
74	    ]);
75	    const sortKey = (c: [number, number]) => `${c[0]},${c[1]}`;
76	    expect(result.slice().sort((a, b) => sortKey(a).localeCompare(sortKey(b)))).toEqual(
77	      [
78	        [-6, -4],
79	        [-5, -4],
80	        [-4, -4],
81	      ].sort((a, b) => sortKey(a).localeCompare(sortKey(b)))
82	    );
83	  });
84	});
